// Setting secure cookie flags in Java Servlet:

public void doPost(HttpServletRequest req, HttpServletResponse resp) {
    // After successful authentication:
    HttpSession session = req.getSession(true);
    session.setAttribute("user", authenticatedUser);

    // Find and secure the JSESSIONID cookie
    Cookie[] cookies = req.getCookies();
    if (cookies != null) {
        for (Cookie cookie : cookies) {
            if ("JSESSIONID".equals(cookie.getName())) {
                cookie.setHttpOnly(true);   // Block JavaScript access
                cookie.setSecure(true);     // HTTPS only
                cookie.setPath("/");        // Valid for entire site
                cookie.setMaxAge(1800);     // 30 minute timeout
                resp.addCookie(cookie);
            }
        }
    }

    // Also set via response header for SameSite:
    resp.setHeader("Set-Cookie", 
        "JSESSIONID=" + session.getId() 
        + "; HttpOnly; Secure; SameSite=Strict; Path=/");
}

// Setting CSP in Java Servlet:
response.setHeader("Content-Security-Policy",
    "default-src 'self'; " +
    "script-src 'self' https://cdn.example.com; " +
    "style-src 'self' 'unsafe-inline'; " +
    "img-src *; " +
    "connect-src 'self'");

// What this policy does:
// default-src 'self'    -> Only load resources from our domain
// script-src 'self' cdn -> Scripts only from our domain or our CDN
// style-src 'self' unsafe-inline -> Styles from us + inline styles OK
// img-src *             -> Images from anywhere (flexible)
// connect-src 'self'    -> AJAX only to our own server

// XSS BLOCKED by CSP:
// Attacker injects: <script>alert(1)</script>
// Browser: "This is an inline script. CSP says script-src 'self'.
