function sanitizeInput(input) {
    return input
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;')
        .replace(/'/g, '&#x27;');
}

// Using regex to strip script tags:
function stripScripts(input) {
    return input.replace(/<script[^>]*>[\\s\\S]*?<\\/script>/gi, '');
}

