import java.security.SecureRandom;
import java.util.Base64;
import javax.servlet.http.*;
import java.io.*;

public class SecureTransferServlet extends HttpServlet {

    // Generate cryptographically random token
    private String generateToken() {
        SecureRandom random = new SecureRandom();
        byte[] bytes = new byte[32];
        random.nextBytes(bytes);
        return Base64.getUrlEncoder().encodeToString(bytes);
    }

    // GET: Show transfer form WITH CSRF token
    protected void doGet(HttpServletRequest req, HttpServletResponse resp)
            throws IOException {
        String token = generateToken();
        req.getSession().setAttribute("csrf_token", token);

        PrintWriter out = resp.getWriter();
        out.println("<form action='/transfer' method='POST'>");
        out.println("<input type='hidden' name='csrf_token' value='" + token + "'>");
        out.println("To: <input name='to_account'>");
        out.println("Amount: <input name='amount'>");
        out.println("<button>Transfer</button>");
        out.println("</form>");
    }

    // POST: Validate CSRF token BEFORE processing
    protected void doPost(HttpServletRequest req, HttpServletResponse resp)
            throws IOException {
        String sessionToken = (String) req.getSession().getAttribute("csrf_token");
        String formToken = req.getParameter("csrf_token");

        // Validate token
        if (sessionToken == null || !sessionToken.equals(formToken)) {
            resp.sendError(403, "Request rejected - invalid security token");
            return;  // STOP! Do not process the transfer.
        }

        // Token valid - process the transfer
        String toAccount = req.getParameter("to_account");
        int amount = Integer.parseInt(req.getParameter("amount"));
        transferMoney(getLoggedInUser(req), toAccount, amount);

        // Invalidate used token (one-time use)
        req.getSession().removeAttribute("csrf_token");
    }
}

import javax.servlet.http.*;
