import java.util.logging.Logger;

public class SecureCommentServlet extends HttpServlet {
    private static final Logger log = Logger.getLogger("Security");

    private String encodeHTML(String s) {
        if (s == null) return "";
        return s.replace("&","&amp;").replace("<","&lt;")
                .replace(">","&gt;").replace("\"","&quot;")
                .replace("'","&#x27;");
    }

    private String generateCSRFToken() {
        byte[] b = new byte[32];
        new SecureRandom().nextBytes(b);
        return Base64.getUrlEncoder().encodeToString(b);
    }

    protected void doGet(HttpServletRequest req, HttpServletResponse resp)
            throws IOException {
        // LAYER 3: CSP Header
        resp.setHeader("Content-Security-Policy",
            "default-src 'self'; script-src 'self'; frame-ancestors 'none'");

        // LAYER 4+5: Secure cookies
        resp.setHeader("Set-Cookie", "JSESSIONID=" + req.getSession().getId()
            + "; HttpOnly; Secure; SameSite=Lax; Path=/");

        // LAYER 6: CSRF Token
        String token = generateCSRFToken();
        req.getSession().setAttribute("csrf_token", token);

        PrintWriter out = resp.getWriter();
        out.println("<form method='POST'>");
        out.println("<input type='hidden' name='csrf_token' value='" + token + "'>");
        out.println("Comment: <textarea name='comment'></textarea>");
        out.println("<button>Post</button></form>");

        // Display existing comments with LAYER 1: Output Encoding
        // for (Comment c : getComments()) {
        //     out.println("<p>" + encodeHTML(c.getText()) + "</p>");
        // }
    }

    protected void doPost(HttpServletRequest req, HttpServletResponse resp)
            throws IOException {
        // LAYER 6: CSRF Validation
        String sToken = (String) req.getSession().getAttribute("csrf_token");
        String fToken = req.getParameter("csrf_token");
        if (sToken == null || !sToken.equals(fToken)) {
            log.warning("CSRF attempt from " + req.getRemoteAddr());
            resp.sendError(403);
            return;
        }

        // LAYER 2: Input Validation
        String comment = req.getParameter("comment");
        if (comment == null || comment.length() > 1000) {
            resp.sendError(400, "Invalid comment");
            return;
        }

        // Save to database (use PreparedStatement!)
        // LAYER 1: Encode on OUTPUT, not on input
        // Store raw comment, encode when displaying
        log.info("New comment from " + req.getRemoteAddr());
    }
}

